#include <iostream>

int main() {
    int n;
    std::cin >> n;

    int* arr = new int[n];
    for (int i = 0; i < n; ++i)
        std::cin >> arr[i];

    int sum = 0;
    for (int i = 0; i < n; ++i)
        sum += arr[i];

    std::cout << "Sum: " << sum << "\n";

    delete[] arr;
    arr = nullptr;
    return 0;
}

