solution_code:
#include <iostream>

int computeMin(int* arr, int n) {
    int minVal = arr[0];
    for (int i = 1; i < n; ++i)
        if (arr[i] < minVal)
            minVal = arr[i];
    return minVal;
}

int main() {
    int n;
    std::cin >> n;

    int* arr = new int[n];
    for (int i = 0; i < n; ++i)
        std::cin >> arr[i];

    int minVal = computeMin(arr, n);
    std::cout << "Count: " << n << "\n";
    std::cout << "Min: " << minVal << "\n";

    delete[] arr;
    return 0;
}
